from collections import deque

class Solution:
    def shortestDistanceAfterQueries(self, n: int, queries: List[List[int]]) -> List[int]:
        # Initialize the graph with the initial roads
        graph = [[] for _ in range(n)]
        for i in range(n - 1):
            graph[i].append(i + 1)

        answer = []
        for u, v in queries:
            graph[u].append(v)
            # Use BFS to find the shortest path from 0 to n-1
            dist = [-1] * n
            q = deque()
            q.append(0)
            dist[0] = 0
            while q:
                node = q.popleft()
                for neighbor in graph[node]:
                    if dist[neighbor] == -1:
                        dist[neighbor] = dist[node] + 1
                        q.append(neighbor)
            answer.append(dist[n - 1])
        return answer
